import { useContext, useEffect, useState } from "react"
import axios from 'axios'
import InitialListing from "../components/InitialListing"
import { UserContext } from "../context/UserContext"
import { Navigate } from "react-router-dom"

const ShopPage =()=>{
    const [allItems ,setAllItems] = useState([])
    const {user ,ready} = useContext(UserContext)
    const [genderOpt ,setGenderOpt] = useState('all')
    useEffect(()=>{
        if(user)
        {
            const fetchData =async()=>{
                try {
                    axios.defaults.headers.common.Authorization = `Bearer ${user?.token}`
                    const response = await axios.get('items/getallitems')
                    setAllItems(response.data)          
                    
                } catch (error) {
                    console.log(error)
                }
            }
            fetchData()
        }
    },[user])
        
    if (ready && !user) {
        return <Navigate to={"/register"} />;
      }
      const  handleGender =(value)=>{
        setGenderOpt(value)
      }
      return <div>
        <div className="flex justify-center">
        <h1 className="text-4xl font-bold tracking-wider">SHOP </h1>
        </div>
        <div className="flex justify-center mt-8">
            <div className="flex justify-around w-96">
                <button className="border border-black p-2 pl-5 pr-5 font-bold tracking-widest" onClick={()=>{handleGender('all')}}>All</button>
                <button className="border border-black p-2 pl-5 pr-5 font-bold tracking-widest" onClick={()=>{handleGender('male')}} >Men</button>
                <button className="border border-black p-2 pl-5 pr-5 font-bold tracking-widest" onClick={()=>{handleGender('female')}}>Women</button>
            </div>
        </div>
        <div className="mt-2 grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-4">
            {
                genderOpt === "all" && (
                    allItems.map((item ,index)=>{
                        return (
                            <InitialListing props={item} key={index} />
                        )
                    })
                )
            }
                {
                genderOpt === "male" && (
                    allItems.filter((data)=>data.gender==="male").map((item ,index)=>{
                        return (
                            <InitialListing props={item} key={index} />
                        )
                    })
                )
            }

{
                genderOpt === "female" && (
                    allItems.filter((data)=>data.gender=="female").map((item ,index)=>{
                        return (
                            <InitialListing props={item} key={index} />
                        )
                    })
                )
            }           

           
        </div>
    </div>
}

export default ShopPage
